import scala.collection.mutable

object Solution {
    private val MOD: Long = 1000000007L
    private var fact: Array[Long] = Array.empty[Long]
    private var invFact: Array[Long] = Array.empty[Long]

    /**
     * Modular exponentiation: (base^exp) % MOD
     */
    private def power(base: Long, exp: Long): Long = {
        var res: Long = 1
        var b: Long = base % MOD
        var e: Long = exp
        while (e > 0) {
            if (e % 2 == 1) {
                res = (res * b) % MOD
            }
            b = (b * b) % MOD
            e /= 2
        }
        res
    }

    /**
     * Modular inverse using Fermat's Little Theorem: n^(MOD-2) % MOD
     */
    private def inverse(n: Long): Long = power(n, MOD - 2)

    /**
     * Precomputes factorials and inverse factorials up to maxN.
     */
    private def precomputeFactorials(maxN: Int): Unit = {
        fact = Array.fill(maxN + 1)(0L)
        invFact = Array.fill(maxN + 1)(0L)

        fact(0) = 1L
        for (i <- 1 to maxN) {
            fact(i) = (fact(i - 1) * i) % MOD
        }

        invFact(maxN) = inverse(fact(maxN))
        for (i <- maxN - 1 down to 0) {
            invFact(i) = (invFact(i + 1) * (i + 1)) % MOD
        }
    }

    /**
     * Calculates nCk mod MOD
     */
    private def combinations(n: Int, k: Int): Long = {
        if (k < 0 || k > n) return 0L
        if (n < 0) return 0L // Should not happen given problem constraints

        // Check if precomputation is done up to n
        if (n >= fact.length) {
             // If somehow called with n larger than precomputed, we must calculate on the fly or handle error.
             // Given constraints N <= 10^5, this path should not be taken if setup is correct.
             throw new IllegalStateException("Factorials not precomputed for required size.")
        }

        val num = fact(n)
        val den = (invFact(k) * invFact(n - k)) % MOD
        (num * den) % MOD
    }

    /**
     * Main solving function.
     */
    def solve(n: Long, pos: Long, k: Long): Long = {
        // Precompute factorials up to N
        precomputeFactorials(n.toInt)

        // L: number of people to the left of POS (0 to POS-1)
        val L = pos.toInt
        // R: number of people to the right of POS (POS+1 to N-1)
        val R = (n - 1 - pos).toInt
        val K = k.toInt

        var totalWaysLR: Long = 0L

        // We need C_L + C_R = K
        // C_L must be in [max(0, K-R), min(L, K)]

        val startCL = Math.max(0, K - R)
        val endCL = Math.min(L, K)

        for (cl <- startCL to endCL) {
            val cr = K - cl

            // Ways to choose CL people from L to be 'L'
            val waysL = combinations(L, cl)

            // Ways to choose CR people from R to be 'R'
            val waysR = combinations(R, cr)

            // Contribution for this pair (CL, CR)
            val currentWays = (waysL * waysR) % MOD

            totalWaysLR = (totalWaysLR + currentWays) % MOD
        }

        // POS itself has 2 independent choices ('L' or 'R')
        // Total answer = 2 * W_LR
        var result = (2 * totalWaysLR) % MOD

        result
    }
