import java.util.Arrays

// Define the modulus globally for helper functions
private val MOD: Long = 1000000007L

// Precomputed factorials and inverse factorials
private var fact: LongArray = Array(0)
private var invFact: LongArray = Array(0)

/**
 * Modular exponentiation: (base^exp) % MOD
 */
private def power(base: Long, exp: Long): Long = {
    var res: Long = 1
    var b: Long = base % MOD
    var e: Long = exp
    while (e > 0) {
        if (e % 2 == 1) {
            res = (res * b) % MOD
        }
        b = (b * b) % MOD
        e /= 2
    }
    res
}

/**
 * Modular multiplicative inverse using Fermat's Little Theorem: n^(MOD-2) % MOD
 */
private def modInverse(n: Long): Long = power(n, MOD - 2)

/**
 * Precomputes factorials and inverse factorials up to maxN
 */
private def precompute(maxN: Int): Unit = {
    fact = new LongArray(maxN + 1)
    invFact = new LongArray(maxN + 1)
    fact(0) = 1
    for (i <- 1 to maxN) {
        fact(i) = (fact(i - 1) * i) % MOD
    }

    invFact(maxN) = modInverse(fact(maxN))
    for (i <- (maxN - 1) downTo 0) {
        invFact(i) = (invFact(i + 1) * (i + 1)) % MOD
    }
}

/**
 * Calculates nCr % MOD
 */
private def combinations(n: Int, r: Int): Long = {
    if (r < 0 || r > n) return 0L
    if (r == 0 || r == n) return 1L
    if (r > n / 2) return combinations(n, n - r)

    // C(n, r) = n! / (r! * (n-r)!)
    var numerator = fact(n)
    var denominator = (invFact(r) * invFact(n - r)) % MOD

    (numerator * denominator) % MOD
}


/**
 * Main solving function
 */
def solve(n: Long, pos: Long, k: Long): Long = {
    val N = n.toInt
    val Pos = pos.toInt
    val K = k.toInt

    // Precompute factorials up to N, which is the maximum possible value for n in combinations
    precompute(N)

    // L: number of people to the left (indices 0 to pos-1)
    val L = Pos
    // R: number of people to the right (indices pos+1 to n-1)
    val R = N - 1 - Pos

    var totalWaysOthers: Long = 0L

    // We need l_seen + r_seen = K
    // l_seen must be in [0, L]
    // r_seen must be in [0, R], so l_seen must be in [K - R, K]

    val startL = Math.max(0, K - R)
    val endL = Math.min(K, L)

    for (lSeen <- startL to endL) {
        val rSeen = K - lSeen

        // Ways to choose lSeen people from L to be seen (must choose 'L')
        val waysL = combinations(L, lSeen)

        // Ways to choose rSeen people from R to be seen (must choose 'R')
        val waysR = combinations(R, rSeen)

        // Total ways for this combination: C(L, lSeen) * C(R, rSeen)
        var currentWays = (waysL * waysR) % MOD

        totalWaysOthers = (totalWaysOthers + currentWays) % MOD
    }

    // The person at 'pos' can choose 'L' or 'R' (2 independent choices).
    // Result = 2 * totalWaysOthers
    val finalResult = (totalWaysOthers * 2) % MOD

    finalResult
}
